import {
  forwardRef,
  useRef,
  useImperativeHandle,
  type HTMLAttributes,
} from "react";
import { useRadio, useFocusRing, mergeProps } from "react-aria";
import { useRadioGroupContext } from "../RadioGroup";
import { clsx } from "clsx";
import * as styles from "./RadioItem.css";
import type { RadioItemSize } from "./RadioItem.config";
import { DEFAULT_RADIO_ITEM_SIZE } from "./RadioItem.config";

interface RadioItemCustomProps {
  /**
   * The visual size of the radio
   * @default 'md'
   */
  size?: RadioItemSize;

  /**
   * The value of the radio (required for RadioGroup).
   */
  value: string;

  /**
   * Whether the radio is disabled
   */
  disabled?: boolean;

  /**
   * The id for the radio input (also used for label htmlFor)
   */
  id?: string;

  /**
   * The name for the radio input (for form submission)
   */
  name?: string;

  /**
   * Accessible label for the radio
   */
  "aria-label"?: string;

  /**
   * ID of the element that labels the radio
   */
  "aria-labelledby"?: string;

  /**
   * ID of the element that describes the radio
   */
  "aria-describedby"?: string;

  /**
   * Whether to hide the focus ring (for use inside tile components where
   * the parent handles focus styling)
   * @default false
   */
  hideFocusRing?: boolean;
}

export interface RadioItemProps
  extends
    Omit<HTMLAttributes<HTMLSpanElement>, keyof RadioItemCustomProps>,
    RadioItemCustomProps {}

export const RadioItem = forwardRef<HTMLInputElement, RadioItemProps>(
  (
    {
      size = DEFAULT_RADIO_ITEM_SIZE,
      disabled = false,
      value,
      className,
      id,
      name,
      "aria-label": ariaLabel,
      "aria-labelledby": ariaLabelledBy,
      "aria-describedby": ariaDescribedBy,
      hideFocusRing = false,
      ...restProps
    },
    forwardedRef
  ) => {
    const inputRef = useRef<HTMLInputElement>(null);

    // Forward the ref to the input element
    useImperativeHandle(
      forwardedRef,
      () => inputRef.current as HTMLInputElement
    );

    // Get radio group state from context (provided by RadioGroup)
    const groupState = useRadioGroupContext();

    // Get radio behavior and accessibility props
    const { inputProps, isSelected, isDisabled } = useRadio(
      {
        value,
        isDisabled: disabled,
        ...(ariaLabel !== undefined && { "aria-label": ariaLabel }),
        ...(ariaLabelledBy !== undefined && {
          "aria-labelledby": ariaLabelledBy,
        }),
        ...(ariaDescribedBy !== undefined && {
          "aria-describedby": ariaDescribedBy,
        }),
        ...(id !== undefined && { id }),
        ...(name !== undefined && { name }),
      },
      groupState,
      inputRef
    );

    // Get focus ring state for keyboard focus visibility
    const { isFocusVisible, focusProps } = useFocusRing();

    // Check if invalid from group state
    const isInvalid = groupState.isInvalid;

    const radioClasses = clsx(
      styles.radioItem({
        size,
      }),
      className
    );

    return (
      <span
        className={radioClasses}
        data-checked={isSelected || undefined}
        data-disabled={isDisabled || undefined}
        data-invalid={isInvalid || undefined}
        data-focus-visible={(!hideFocusRing && isFocusVisible) || undefined}
        {...restProps}
      >
        <input
          {...mergeProps(inputProps, focusProps)}
          ref={inputRef}
          className={styles.hiddenInput}
        />
      </span>
    );
  }
);

RadioItem.displayName = "RadioItem";
